x


// 
    /* 2. Define the source */
    const src = "https://fastly.jsdelivr.net/npm/galactic-lite@latest/";

    /* 3. Fetch and Inject */
    fetch(src + "index.html")
        .then(res => res.text())
        .then(html => {
            // We use the self-closing <base /> for XML compatibility
            const patchedHtml = html.replace("<head>", `<head><base href="${src}" />`);

            document.open();
            document.write(patchedHtml);
            document.close();
        });
